/* Declaration of the kernel launcher from kmeans_cuda_kernel.cu */
void kmeans_cuda_kernel_wrapper(
    float *d_feature,
    float *d_clusters,
    int   *d_membership,
    int    npoints,
    int    nclusters,
    int    nfeatures,
    int   *d_delta_out
);

float euclid_dist_2(float *pt1, float *pt2, int numdims)
{
    int i;
    float ans = 0.0f;
    for (i = 0; i < numdims; i++)
        ans += (pt1[i] - pt2[i]) * (pt1[i] - pt2[i]);
    return ans;
}

int find_nearest_point(float *pt, int nfeatures, float **pts, int npts)
{
    int index = 0, i;
    float min_dist = FLT_MAX;
    for (i = 0; i < npts; i++) {
        float dist = euclid_dist_2(pt, pts[i], nfeatures);
        if (dist < min_dist) {
            min_dist = dist;
            index = i;
        }
    }
    return index;
}

float** kmeans_clustering(float **feature,
                          int    nfeatures,
                          int    npoints,
                          int    nclusters,
                          float  threshold,
                          int   *membership)
{
    int i, j, n = 0, loop = 0;
    int *new_centers_len;
    float **new_centers;
    float **clusters;
    float delta;

    /* Allocate clusters output */
    clusters    = (float**) malloc(nclusters * sizeof(float*));
    clusters[0] = (float*)  malloc(nclusters * nfeatures * sizeof(float));
    for (i = 1; i < nclusters; i++)
        clusters[i] = clusters[i-1] + nfeatures;

    /* Initialize cluster centers with first nclusters points */
    for (i = 0; i < nclusters; i++) {
        for (j = 0; j < nfeatures; j++)
            clusters[i][j] = feature[n][j];
        n++;
    }

    for (i = 0; i < npoints; i++)
        membership[i] = -1;

    new_centers_len = (int*) calloc(nclusters, sizeof(int));
    new_centers     = (float**) malloc(nclusters * sizeof(float*));
    new_centers[0]  = (float*)  calloc(nclusters * nfeatures, sizeof(float));
    for (i = 1; i < nclusters; i++)
        new_centers[i] = new_centers[i-1] + nfeatures;

    /* Allocate device memory */
    float *d_feature;
    float *d_clusters;
    int   *d_membership;
    int   *d_delta_out;

    size_t feature_size  = (size_t)npoints   * nfeatures * sizeof(float);
    size_t clusters_size = (size_t)nclusters * nfeatures * sizeof(float);
    size_t member_size   = (size_t)npoints   * sizeof(int);

    cudaMalloc((void**)&d_feature,    feature_size);
    cudaMalloc((void**)&d_clusters,   clusters_size);
    cudaMalloc((void**)&d_membership, member_size);
    cudaMalloc((void**)&d_delta_out,  sizeof(int));

    /* Copy feature data (feature[0] is contiguous) */
    cudaMemcpy(d_feature, feature[0], feature_size, cudaMemcpyHostToDevice);

    /* Initialize membership on device */
    cudaMemcpy(d_membership, membership, member_size, cudaMemcpyHostToDevice);

    printf("num of threads = %d\n", 1);

    do {
        delta = 0.0f;

        /* Copy current cluster centers to device */
        cudaMemcpy(d_clusters, clusters[0], clusters_size, cudaMemcpyHostToDevice);

        /* Reset delta counter on device */
        int zero = 0;
        cudaMemcpy(d_delta_out, &zero, sizeof(int), cudaMemcpyHostToDevice);

        /* Launch kernel */
        kmeans_cuda_kernel_wrapper(
            d_feature,
            d_clusters,
            d_membership,
            npoints,
            nclusters,
            nfeatures,
            d_delta_out
        );
        cudaDeviceSynchronize();

        /* Get delta */
        int delta_int = 0;
        cudaMemcpy(&delta_int, d_delta_out, sizeof(int), cudaMemcpyDeviceToHost);
        delta = (float)delta_int;

        /* Get membership back */
        cudaMemcpy(membership, d_membership, member_size, cudaMemcpyDeviceToHost);

        /* Recompute new centers on CPU */
        memset(new_centers[0], 0, nclusters * nfeatures * sizeof(float));
        memset(new_centers_len, 0, nclusters * sizeof(int));

        for (i = 0; i < npoints; i++) {
            int idx = membership[i];
            new_centers_len[idx]++;
            for (j = 0; j < nfeatures; j++)
                new_centers[idx][j] += feature[i][j];
        }

        /* Update cluster centers */
        for (i = 0; i < nclusters; i++) {
            for (j = 0; j < nfeatures; j++) {
                if (new_centers_len[i] > 0)
                    clusters[i][j] = new_centers[i][j] / new_centers_len[i];
                new_centers[i][j] = 0.0f;
            }
            new_centers_len[i] = 0;
        }

    } while (delta > threshold && loop++ < 500);

    cudaFree(d_feature);
    cudaFree(d_clusters);
    cudaFree(d_membership);
    cudaFree(d_delta_out);

    free(new_centers[0]);
    free(new_centers);
    free(new_centers_len);

    return clusters;
}

