#include <stdio.h>
#include <cuda.h>

#ifndef FLT_MAX
#define FLT_MAX 3.40282347e+38
#endif

/*
 * Each thread handles one point.
 * Finds the nearest cluster center and updates membership.
 * Atomically increments delta if membership changed.
 */
__global__ void kmeans_kernel(
    float *feature,      /* [npoints * nfeatures] row-major */
    float *clusters,     /* [nclusters * nfeatures] row-major */
    int   *membership,   /* [npoints] */
    int    npoints,
    int    nclusters,
    int    nfeatures,
    int   *delta_out     /* single int, atomically incremented */
)
{
    int point_id = blockIdx.x * blockDim.x + threadIdx.x;
    if (point_id >= npoints) return;

    float min_dist = FLT_MAX;
    int   index    = 0;

    for (int c = 0; c < nclusters; c++) {
        float dist = 0.0f;
        for (int f = 0; f < nfeatures; f++) {
            float diff = feature[point_id * nfeatures + f]
                       - clusters[c * nfeatures + f];
            dist += diff * diff;
        }
        if (dist < min_dist) {
            min_dist = dist;
            index    = c;
        }
    }

    if (membership[point_id] != index) {
        atomicAdd(delta_out, 1);
        membership[point_id] = index;
    }
}

void kmeans_cuda_kernel_wrapper(
    float *d_feature,
    float *d_clusters,
    int   *d_membership,
    int    npoints,
    int    nclusters,
    int    nfeatures,
    int   *d_delta_out
)
{
    int block_size = 256;
    int grid_size  = (npoints + block_size - 1) / block_size;

    kmeans_kernel<<<grid_size, block_size>>>(
        d_feature,
        d_clusters,
        d_membership,
        npoints,
        nclusters,
        nfeatures,
        d_delta_out
    );
}
